#include<bits/stdc++.h>
#define ll long long
using namespace std;
const int MAXN=3e6+5;
ll k,n,a[MAXN],maxdq[MAXN],mindq[MAXN],head_max,head_min,tail_max,tail_min,ans,p;
int main(void){
    scanf("%lld%lld",&k,&n),ans=0,maxdq[1]=1,mindq[1]=1,p=1,head_max=1,tail_max=1,head_min=1,tail_min=1;
    for(int i=1;i<=n;i++)scanf("%lld",&a[i]);
    for(int i=2;i<=n;i++){
        while(head_max<=tail_max&&a[maxdq[tail_max]]<a[i])tail_max--;
        while(head_min<=tail_min&&a[mindq[tail_min]]>a[i])tail_min--;
        maxdq[++tail_max]=i,mindq[++tail_min]=i;
        while(a[maxdq[head_max]]-a[mindq[head_min]]>k){
            if(maxdq[head_max]<mindq[head_min])p=maxdq[head_max]+1,head_max++;
            else p=mindq[head_min]+1,head_min++;
        }ans=max(ans,i-p+1);
    }printf("%lld",ans);
    return false;
}
